<span class="line">                <span class="token class-name">EncryptionUtil</span><span class="token punctuation">.</span><span class="token function">getSha3Hash</span><span class="token punctuation">(</span><span class="token string">"|"</span><span class="token punctuation">,</span> mqtt<span class="token punctuation">.</span><span class="token function">getClientId</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> mqtt<span class="token punctuation">.</span><span class="token function">getUserName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">checkIsMqttCredentials</span><span class="token punctuation">(</span>credentials<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">var</span> validationResult <span class="token operator">=</span> <span class="token function">validateMqttCredentials</span><span class="token punctuation">(</span>mqtt<span class="token punctuation">,</span> credentials<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token constant">VALID</span><span class="token punctuation">.</span><span class="token function">equals</span><span class="token punctuation">(</span>validationResult<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
