<span class="line">        <span class="token keyword">switch</span> <span class="token punctuation">(</span>credentials<span class="token punctuation">.</span><span class="token function">getCredentialsType</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">case</span> <span class="token constant">ACCESS_TOKEN</span><span class="token operator">:</span></span>
<span class="line">                <span class="token keyword">return</span> <span class="token function">getDeviceInfo</span><span class="token punctuation">(</span>credentials<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token keyword">case</span> <span class="token constant">MQTT_BASIC</span><span class="token operator">:</span></span>
<span class="line">                <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token constant">VALID</span><span class="token punctuation">.</span><span class="token function">equals</span><span class="token punctuation">(</span><span class="token function">validateMqttCredentials</span><span class="token punctuation">(</span>mqtt<span class="token punctuation">,</span> credentials<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
